// ============================================
// 📊 Formater les offres d'emploi v2
// ============================================

const offresData = $node['📋 Chercher Offres IDF'].json;
const resultats = offresData.resultats || [];

const ROME_SECTEURS = {
  'G1602': 'Restauration',
  'G1603': 'Restauration',
  'G1605': 'Restauration',
  'N1103': 'Logistique',
  'N1105': 'Logistique',
  'F1702': 'BTP - Maçonnerie',
  'F1603': 'BTP - Plomberie',
  'F1613': 'BTP - Étanchéité',
  'K2204': 'Nettoyage',
  'D1507': 'Commerce - Mise en rayon',
  'D1106': 'Commerce - Vente',
  'D1102': 'Boulangerie',
  'A1203': 'Paysagisme',
  'I1606': 'Carrosserie',
  'K1303': 'Petite enfance',
  'H2301': 'Production industrielle',
  'I1304': 'Maintenance industrielle'
};

const offresFormatees = resultats.map(offre => {
  const codeRome = offre.romeCode || '';
  return {
    id: offre.id,
    titre: offre.intitule,
    entreprise: offre.entreprise?.nom || 'Non communiqué',
    lieu: offre.lieuTravail?.libelle || 'Non précisé',
    code_postal: offre.lieuTravail?.codePostal || '',
    contrat: offre.typeContratLibelle || offre.typeContrat || '',
    nature_contrat: offre.natureContrat || '',
    est_alternance: offre.alternance === true,
    salaire: offre.salaire?.libelle || 'Non communiqué',
    experience: offre.experienceExige || 'Non précisé',
    competences: (offre.competences || []).map(c => c.libelle).join(', '),
    description_courte: (offre.description || '').substring(0, 300) + '...',
    url_offre: offre.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${offre.id}`,
    date_creation: offre.dateCreation,
    code_rome: codeRome,
    metier: offre.romeLibelle,
    secteur_ombres: ROME_SECTEURS[codeRome] || 'Autre',
    qualification: offre.qualificationLibelle || '',
    niveau_langue_requis: (offre.langues || []).map(l => `${l.libelle}: ${l.exigence}`).join(', ') || 'Non précisé',
    permis_requis: (offre.permis || []).map(p => p.libelle).join(', ') || 'Non requis',
    debutant_accepte: offre.experienceExige === 'D',
    formations: (offre.formations || []).map(f => f.niveauLibelle).join(', ') || 'Non précisé'
  };
});

const stats = {
  total_disponibles: offresData.contentRange?.maxResults || resultats.length,
  nb_retournes: offresFormatees.length,
  nb_alternance: offresFormatees.filter(o => o.est_alternance).length,
  nb_debutant_accepte: offresFormatees.filter(o => o.debutant_accepte).length,
  par_secteur: offresFormatees.reduce((acc, o) => {
    acc[o.secteur_ombres] = (acc[o.secteur_ombres] || 0) + 1;
    return acc;
  }, {}),
  par_contrat: offresFormatees.reduce((acc, o) => {
    acc[o.contrat] = (acc[o.contrat] || 0) + 1;
    return acc;
  }, {})
};

return [{ json: { ...stats, offres: offresFormatees } }];

// ============================================
// 🎓 Formater La Bonne Alternance
// ============================================

const data = $node['📋 Chercher Alternance IDF'].json;
const jobs = data.jobs || [];
const recruiters = data.recruiters || [];
const warnings = data.warnings || [];

// --- Formater les offres d'alternance ---
const offresFormatees = jobs.map(job => ({
  source: job.identifier?.partner_label || 'Inconnu',
  id_partenaire: job.identifier?.partner_job_id || '',
  id_lba: job.identifier?.id || null,
  titre: job.offer?.title || '',
  description_courte: (job.offer?.description || '').substring(0, 300) + '...',
  entreprise: job.workplace?.name || 'Non communiqué',
  enseigne: job.workplace?.brand || '',
  raison_sociale: job.workplace?.legal_name || '',
  siret: job.workplace?.siret || '',
  effectif: job.workplace?.size || '',
  ville: job.workplace?.location?.city || '',
  code_postal: job.workplace?.location?.zipCode || '',
  site_web: job.workplace?.website || '',
  naf: job.workplace?.domain?.naf?.code || '',
  naf_label: job.workplace?.domain?.naf?.label || '',
  opco: job.workplace?.domain?.opco || '',
  type_contrat: (job.contract?.type || []).join(', '),
  date_debut: job.contract?.start || '',
  duree_mois: job.contract?.duration || null,
  mode_travail: job.contract?.remote || '',
  diplome_vise: job.offer?.target_diploma?.label || '',
  niveau_diplome: job.offer?.target_diploma?.level || '',
  codes_rome: (job.offer?.rome_codes || []).join(', '),
  competences_attendues: (job.offer?.desired_skills || []).join('; '),
  competences_a_acquerir: (job.offer?.to_be_acquired_skills || []).join('; '),
  conditions_acces: (job.offer?.access_conditions || []).join('; '),
  nb_postes: job.offer?.opening_count || 1,
  date_creation: job.offer?.publication?.creation || '',
  date_expiration: job.offer?.publication?.expiration || '',
  url_candidature: job.apply?.url || '',
  telephone: job.apply?.phone || '',
  est_delegue_cfa: job.is_delegated || false
}));

// --- Formater les recruteurs potentiels ---
const recruteursFormates = recruiters.map(r => ({
  id: r.identifier?.id || '',
  source: r.identifier?.partner_label || 'recruteurs_lba',
  entreprise: r.workplace?.name || 'Non communiqué',
  enseigne: r.workplace?.brand || '',
  raison_sociale: r.workplace?.legal_name || '',
  siret: r.workplace?.siret || '',
  effectif: r.workplace?.size || '',
  ville: r.workplace?.location?.city || '',
  code_postal: r.workplace?.location?.zipCode || '',
  site_web: r.workplace?.website || '',
  naf: r.workplace?.domain?.naf?.code || '',
  naf_label: r.workplace?.domain?.naf?.label || '',
  opco: r.workplace?.domain?.opco || '',
  url_candidature: r.apply?.url || '',
  telephone: r.apply?.phone || ''
}));

// --- Stats ---
const parSource = offresFormatees.reduce((acc, o) => {
  acc[o.source] = (acc[o.source] || 0) + 1;
  return acc;
}, {});

const parContrat = offresFormatees.reduce((acc, o) => {
  const t = o.type_contrat || 'Non précisé';
  acc[t] = (acc[t] || 0) + 1;
  return acc;
}, {});

return [{
  json: {
    source: 'La Bonne Alternance',
    zone: 'Paris + 20km',
    nb_offres: offresFormatees.length,
    nb_recruteurs: recruteursFormates.length,
    par_source: parSource,
    par_contrat: parContrat,
    warnings: warnings,
    offres: offresFormatees,
    recruteurs: recruteursFormates
  }
}];
